/**
 * The store's type definition with a getter, setter, and subscribe property.
 * @public
 */
export type Store<T> = {
    getState: () => T;
    setState: (action: T | ((prev: T) => T)) => void;
    subscribe: (callback: () => void) => () => void;
};
/**
 * Creates a store with an initial state and provides getters and setters and subscriptions for the store.
 * @public
 */
export declare function createStore<T>(initialState: T): Store<T>;
